import './Options.scss';

import { getLoading, getPreparedOptions } from ':components/Select/helpers';
import type { Option } from ':components/Select/Select.types';
import { CheckboxType } from ':components/Select/Select.types';
import { Typography } from ':components/Typography';
import type { JSX } from 'react';
import React from 'react';

import { classNames } from '../../../../helpers/classnames';
import { Item } from '../Item';

export interface OptionsProps<T> {
	selectedItems: Array<Option<T>>;
	optionsData: Array<Option<T>>;
	selectAll: boolean;
	filter: boolean;
	filterValue: string;
	filterFunction: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>;
	selectAllIndex: number;
	optionsClassName: string;
	multiple: boolean;
	itemClassName: string;
	onMultiselectItem: (item: Option<T>) => () => void;
	onManualClickOption: (option: T) => void;
	onSelectItem: (item: Option<T>) => () => void;
	focusedIndex: number;
	handleSelectAll: () => void;
	makeOption: (option: T, selected?: boolean) => React.JSX.Element;
	showTooltip: boolean;
	defaultMakeOption: <T>(option: T, showTooltip: boolean) => React.JSX.Element;
	selectAllText: string;
	loading: boolean;
	loadingText: React.ReactNode;
	loadingContent: string | React.ReactNode;
	noOptionsText: string;
	optionsRef: React.MutableRefObject<HTMLDivElement>;
	selectStatus: CheckboxType;
	makeOptionWrapper?: (
		option: T,
		selected?: boolean,
		defaultProps?: {
			key: string | number;
			className: string;
			onClick: () => void;
			children: React.JSX.Element;
		},
	) => React.JSX.Element;
	groups?: Array<Option<string>>;
	dataTestId: string;
}

export const Options = <T,>({
	selectedItems,
	optionsData,
	selectAll,
	filter,
	filterValue,
	filterFunction,
	selectAllIndex,
	optionsClassName,
	multiple,
	itemClassName,
	onMultiselectItem,
	onManualClickOption,
	onSelectItem,
	focusedIndex,
	handleSelectAll,
	makeOption,
	showTooltip,
	defaultMakeOption,
	selectAllText,
	loading,
	loadingText,
	loadingContent,
	noOptionsText,
	optionsRef,
	selectStatus,
	makeOptionWrapper,
	groups = [],
	dataTestId,
}: OptionsProps<T>): React.JSX.Element => {
	const options: Array<Option<T>> = getPreparedOptions(optionsData, filter, filterValue, filterFunction);

	let innerContent: React.ReactNode = null;
	let globalOptionIndex = 0;

	// selectAll теперь всегда в самом верху, независимо от группировки
	const selectAllOption = selectAll ? (
		<Item
			key={selectAllIndex}
			optionId={`${dataTestId}-option-select-all`}
			option={{ id: selectAllIndex, value: selectAllText as T }}
			isSelected={selectStatus}
			multiple={multiple}
			selectAll={true}
			itemClassName={itemClassName}
			onMultiselectItem={onMultiselectItem}
			onManualClickOption={onManualClickOption}
			onSelectItem={onSelectItem}
			focusedIndex={focusedIndex}
			optionIndex={-1}
			handleSelectAll={handleSelectAll}
			showTooltip={showTooltip}
			defaultMakeOption={defaultMakeOption}
			makeOptionWrapper={makeOptionWrapper}
		/>
	) : null;

	if (loading) {
		innerContent = getLoading(loadingText || loadingContent);
	} else if (options.length === 0) {
		const emptySearchClass = classNames(itemClassName, itemClassName + '_empty');
		innerContent = (
			<div className={emptySearchClass}>
				<Typography variant="body2" ellipsis={true}>
					{noOptionsText}
				</Typography>
			</div>
		);
	} else if (groups.length > 0) {
		const groupsContent = groups.flatMap(group => {
			const groupOptions = options.filter(
				opt =>
					// @ts-ignore
					opt.value?.groupID === group.id,
			);
			if (groupOptions.length === 0) {
				return null;
			}

			const groupBlock = [
				<div key={`group-title-${group.id}`} className="dsb__select__options__group-title">
					<Typography variant="body2">{group.value}</Typography>
				</div>,
				...groupOptions.map(item => {
					const rendered = (
						<Item
							key={item.id}
							optionId={`${dataTestId}-option-${item.id}`}
							option={item}
							isSelected={selectedItems.some(i => i.id === item.id) ? CheckboxType.CHECKED : CheckboxType.UNCHECKED}
							multiple={multiple}
							selectAll={false}
							itemClassName={itemClassName}
							onMultiselectItem={onMultiselectItem}
							onManualClickOption={onManualClickOption}
							onSelectItem={onSelectItem}
							focusedIndex={focusedIndex}
							optionIndex={globalOptionIndex}
							handleSelectAll={handleSelectAll}
							makeOption={makeOption}
							showTooltip={showTooltip}
							defaultMakeOption={defaultMakeOption}
							makeOptionWrapper={makeOptionWrapper}
						/>
					);
					globalOptionIndex++;
					return rendered;
				}),
			];
			return groupBlock;
		});
		innerContent = (
			<>
				{selectAllOption}
				{groupsContent}
			</>
		);
	} else {
		// обычный список
		innerContent = (
			<>
				{selectAllOption}
				{options.map((item, index) => (
					<Item
						key={item.id}
						optionId={`${dataTestId}-option-${item.id}`}
						option={item}
						isSelected={selectedItems.some(i => i.id === item.id) ? CheckboxType.CHECKED : CheckboxType.UNCHECKED}
						multiple={multiple}
						selectAll={false}
						itemClassName={itemClassName}
						onMultiselectItem={onMultiselectItem}
						onManualClickOption={onManualClickOption}
						onSelectItem={onSelectItem}
						focusedIndex={focusedIndex}
						optionIndex={index}
						handleSelectAll={handleSelectAll}
						makeOption={makeOption}
						showTooltip={showTooltip}
						defaultMakeOption={defaultMakeOption}
						makeOptionWrapper={makeOptionWrapper}
					/>
				))}
			</>
		);
	}

	return (
		<div
			className={optionsClassName}
			ref={optionsRef}
			role="listbox" /* NOSONAR S6819 - WAI-ARIA listbox pattern, native select doesn't support filter/groups/custom options */
			aria-multiselectable={multiple ? 'true' : undefined}
			id={`${dataTestId}-listbox`}
		>
			{innerContent}
		</div>
	);
};
